const input = $json.body || $json;
const documentId = String(input.documentId || input.document_id || '').trim();
const brandName = String(input.brandName || input.brand_name || 'Unknown Brand').trim();
const sourceName = String(input.sourceName || input.source_name || '').trim();
const rawMarkdown = String(input.rawMarkdown || input.raw_markdown || '').trim();
const model = String(input.model || 'gpt-4o-mini').trim();

if (!documentId) throw new Error('documentId is required');
if (!rawMarkdown) throw new Error('rawMarkdown is required');

const maxChars = Number(input.maxChars || input.max_chars || 90000);
const clippedMarkdown = rawMarkdown.length > maxChars
  ? `${rawMarkdown.slice(0, maxChars)}\n\n[TRUNCATED: original markdown exceeded ${maxChars} characters]`
  : rawMarkdown;

return [{
  json: {
    documentId,
    brandName,
    sourceName,
    rawMarkdown: clippedMarkdown,
    rawMarkdownCharCount: rawMarkdown.length,
    wasTruncated: rawMarkdown.length > maxChars,
    model
  }
}];

const { documentId, brandName, sourceName, rawMarkdown, model, rawMarkdownCharCount, wasTruncated } = $json;

const system = 'You are a senior brand design systems analyst. Return valid JSON only.';
const user = `Analyze the provided design markdown and extract the brand's intended design concept for AI-generated promotional web pages.

The markdown is not only a token source. It defines the design philosophy, visual mood, layout rules, component behavior, depth model, effects, and do/don't rules.

Return valid JSON only. Do not include markdown fences. Do not include explanations outside JSON.

Input:
- brandName: ${brandName}
- sourceName: ${sourceName}
- rawMarkdownCharCount: ${rawMarkdownCharCount}
- wasTruncated: ${wasTruncated}

Design Markdown:
${rawMarkdown}

Required JSON schema:
{
  "brandConcept": "Short description of the brand's core design concept.",
  "visualMood": "Visual atmosphere and emotional tone.",
  "layoutPhilosophy": "How page sections should be arranged and paced.",
  "spacingRhythm": "Spacing density, whitespace usage, section rhythm.",
  "depthAndEffects": "Elevation, shadow, blur, gradients, overlays, image depth, or no-depth rules.",
  "shapeAndRadius": "Corner radius, geometry, image crop style, pill/rectangular preference.",
  "componentStyle": "Button, card, nav, badge, form, CTA, footer style guidance.",
  "motionOrEffects": "Animation or interactive effect guidance if present. If absent, say restrained/no explicit motion.",
  "colorBehavior": "How colors should be used, including primary, accent, background, semantic, and restraint rules.",
  "typographyBehavior": "How typography should feel and be used, including display/body contrast.",
  "dos": ["Concrete rule that should be followed."],
  "donts": ["Concrete rule that should be avoided."],
  "generationGuidance": ["Instruction for an AI page generator."],
  "promoPageImplications": {
    "hero": "How a promo hero should be designed for this MD.",
    "contentSections": "How supporting content sections should look.",
    "cta": "How CTAs should be styled and placed.",
    "legal": "How legal/terms text should be handled.",
    "desktopLayout": "Desktop-specific layout guidance for 1440px viewport."
  },
  "confidence": 0.0
}

Rules:
- Be faithful to the provided markdown.
- Do not invent brand rules that are not supported by the markdown.
- If information is missing, infer conservatively and mention the gap in generationGuidance.
- Focus on what will help an AI generate a web page in the correct style.
- Keep each string concise but specific.
- confidence must be a number from 0 to 1.`;

return [{
  json: {
    documentId,
    brandName,
    sourceName,
    model,
    llmRequest: {
      model,
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: user }
      ],
      temperature: 0.2,
      response_format: { type: 'json_object' }
    }
  }
}];

const normalize = $('Normalize Input').item.json;
const prompt = $('Build Concept Analysis Prompt').item.json;
const response = $json;

const content = response.choices?.[0]?.message?.content
  || response.message?.content
  || response.content
  || response.text
  || response.output_text
  || '';

if (!content) {
  throw new Error('LLM response content is empty');
}

let concept;
try {
  concept = typeof content === 'string' ? JSON.parse(content.replace(/^```json\s*/i, '').replace(/```$/i, '').trim()) : content;
} catch (error) {
  throw new Error(`Failed to parse LLM JSON: ${error.message}`);
}

const required = [
  'brandConcept',
  'visualMood',
  'layoutPhilosophy',
  'depthAndEffects',
  'componentStyle',
  'dos',
  'donts',
  'generationGuidance',
  'promoPageImplications',
  'confidence'
];
const missing = required.filter((key) => concept[key] === undefined || concept[key] === null || concept[key] === '');
if (missing.length) {
  throw new Error(`LLM concept JSON missing fields: ${missing.join(', ')}`);
}

const confidence = Math.max(0, Math.min(1, Number(concept.confidence || 0)));
concept.confidence = confidence;

const implications = concept.promoPageImplications || {};
const guidanceLines = [
  `Brand concept: ${concept.brandConcept}`,
  `Visual mood: ${concept.visualMood}`,
  `Layout philosophy: ${concept.layoutPhilosophy}`,
  `Depth/effects: ${concept.depthAndEffects}`,
  `Shape/radius: ${concept.shapeAndRadius || ''}`,
  `Component style: ${concept.componentStyle}`,
  `Color behavior: ${concept.colorBehavior || ''}`,
  `Typography behavior: ${concept.typographyBehavior || ''}`,
  `Hero: ${implications.hero || ''}`,
  `Content sections: ${implications.contentSections || ''}`,
  `CTA: ${implications.cta || ''}`,
  `Legal: ${implications.legal || ''}`,
  `Desktop layout: ${implications.desktopLayout || ''}`,
  `Do: ${(concept.dos || []).join(' | ')}`,
  `Don't: ${(concept.donts || []).join(' | ')}`,
  `Generation guidance: ${(concept.generationGuidance || []).join(' | ')}`
].filter((line) => !line.endsWith(': ')).join('\n');

return [{
  json: {
    documentId: normalize.documentId,
    brandName: normalize.brandName,
    sourceName: normalize.sourceName,
    model: prompt.model,
    designConceptSummary: concept.brandConcept,
    designConceptJson: concept,
    designPromptContext: guidanceLines,
    confidence
  }
}];
